using System.Runtime.InteropServices;

namespace Compression;

internal static unsafe partial class NativeCompression
{
    [LibraryImport("compresslib")]
    private static partial int compress_buffer(
        byte* input, nuint input_len,
        byte* output, nuint output_len,
        nuint* bytes_written);

    public static int CompressBuffer(
        ReadOnlySpan<byte> input,
        Span<byte> output,
        out nuint bytesWritten)
    {
        fixed (byte* pInput = input)
        fixed (byte* pOutput = output)
        {
            nuint written;
            int result = compress_buffer(
                pInput, (nuint)input.Length,
                pOutput, (nuint)output.Length,
                &written);
            bytesWritten = written;
            return result;
        }
    }
}

